            invIdx:     invIdx >= 0 ? invIdx : 0,
            model:      r.model,
            qty:        parseInt(r.qty) || 0,
            project:    r.project,
            staff:      r.staff,
            returnDate: r.dateReturn,
            date:       r.date,
